import{_ as a,o as e,c as i,a2 as r}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Trait-Based Team Model","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/operating-model/trait-based-team.md","filePath":"ai-native/operating-model/trait-based-team.md"}'),d={name:"ai-native/operating-model/trait-based-team.md"};function s(l,t,n,o,h,p){return e(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="trait-based-team-model" tabindex="-1">Trait-Based Team Model <a class="header-anchor" href="#trait-based-team-model" aria-label="Permalink to &quot;Trait-Based Team Model&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>本模型将 <a href="./../principles/trait-based-teams.html">按 Trait 组队</a> 转换为团队盘点和协作方法。</p><h2 id="trait-不是岗位" tabindex="-1">Trait 不是岗位 <a class="header-anchor" href="#trait-不是岗位" aria-label="Permalink to &quot;Trait 不是岗位&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Person[&quot;一个团队成员&quot;] --&gt; Job[&quot;Job Family&lt;br/&gt;专业基础&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Person --&gt; Primary[&quot;主导 Trait&lt;br/&gt;主要责任&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Person --&gt; Secondary[&quot;辅助 Trait&lt;br/&gt;可跨界贡献&quot;]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Team[&quot;团队&quot;] --&gt; Coverage[&quot;五类 Trait 覆盖&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Team --&gt; Expertise[&quot;必要专业深度&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Team --&gt; Outcome[&quot;端到端产品结果&quot;]</span></span></code></pre></div><p>一个人的岗位可以是工程师，但主导 Trait 可能是 Architect，也可能是 Builder 或 Taste Maker。</p><h2 id="团队盘点" tabindex="-1">团队盘点 <a class="header-anchor" href="#团队盘点" aria-label="Permalink to &quot;团队盘点&quot;">​</a></h2><p>每个 Initiative 启动时，填写：</p><table tabindex="0"><thead><tr><th>Trait</th><th>主导成员</th><th>辅助成员</th><th>当前缺口</th><th>验证方式</th></tr></thead><tbody><tr><td>Builder / Pirate</td><td></td><td></td><td></td><td>原型或交付周期</td></tr><tr><td>Architect</td><td></td><td></td><td></td><td>稳定性、扩展性和债务</td></tr><tr><td>Taste Maker</td><td></td><td></td><td></td><td>体验评审和用户反馈</td></tr><tr><td>Signal Reader</td><td></td><td></td><td></td><td>研究质量和市场证据</td></tr><tr><td>Decision Maker</td><td></td><td></td><td></td><td>决策时效和结果复盘</td></tr></tbody></table><p>主导成员不是唯一执行者，而是确保该视角不会在关键决策中缺席。</p><h2 id="产品阶段与-trait-重心" tabindex="-1">产品阶段与 Trait 重心 <a class="header-anchor" href="#产品阶段与-trait-重心" aria-label="Permalink to &quot;产品阶段与 Trait 重心&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>优先 Trait</th><th>常见风险</th></tr></thead><tbody><tr><td>问题探索</td><td>Signal Reader、Decision Maker</td><td>过早开始实现</td></tr><tr><td>原型验证</td><td>Builder / Pirate、Taste Maker</td><td>做得快但不可用</td></tr><tr><td>产品化</td><td>Architect、Taste Maker</td><td>原型债务拖垮体验</td></tr><tr><td>增长验证</td><td>Signal Reader、Decision Maker</td><td>指标增长但价值不成立</td></tr><tr><td>规模化</td><td>Architect、Decision Maker</td><td>局部效率损害整体系统</td></tr></tbody></table><p>重心变化不代表其他 Trait 可以缺席。</p><h2 id="builder-pirate-与-architect-的协作" tabindex="-1">Builder / Pirate 与 Architect 的协作 <a class="header-anchor" href="#builder-pirate-与-architect-的协作" aria-label="Permalink to &quot;Builder / Pirate 与 Architect 的协作&quot;">​</a></h2><p>速度和可持续性不应变成两个角色互相甩锅。</p><p>每次快速实验应明确：</p><ul><li>哪些是一次性探索代码</li><li>哪些路径如果验证成功必须重构</li><li>谁负责产品化</li><li>重构触发条件和最晚时间</li><li>哪些安全和数据约束从第一天就不能放松</li></ul><p>Architect 不负责无限期清理 Builder 留下的一切；Builder 也要对实验进入生产后的后果负责。</p><h2 id="review" tabindex="-1">Review <a class="header-anchor" href="#review" aria-label="Permalink to &quot;Review&quot;">​</a></h2><p>在 Initiative Review 中增加三个问题：</p><ol><li>哪个 Trait 在本轮发挥了关键作用？</li><li>哪个 Trait 缺席，造成了什么返工或盲点？</li><li>下一阶段需要调整谁的主导责任？</li></ol><p>这些记录用于改善组队，不用于给个人贴永久标签。</p>`,22)])])}const m=a(d,[["render",s]]);export{u as __pageData,m as default};
